export const Schema = z.object({
    主角: z.object({
        母畜币: z.coerce.number().prefault(0),
        联名卡余额: z.coerce.number().prefault(0),
        卡外资产: z.coerce.number().prefault(0),
        道具栏: z.object({
            母猪检疫印章: z.coerce.number().prefault(0),
            母牛检疫印章: z.coerce.number().prefault(0),
            母狗检疫印章: z.coerce.number().prefault(0),
            母畜检疫特供印泥: z.coerce.number().prefault(0),
            转职卡: z.coerce.number().prefault(0),
            重修卡: z.coerce.number().prefault(0),
            重修稳定剂: z.coerce.number().prefault(0),
            公交车经营许可证: z.coerce.number().prefault(0),
            公交车经营保险: z.coerce.number().prefault(0),
            性病康复针剂: z.coerce.number().prefault(0),
            无害人流丸: z.coerce.number().prefault(0),
        }).prefault({}),
        特殊建造: z.record(z.string().describe('房间类型'), z.object({
            位置: z.string().prefault(''),
            面积: z.coerce.number().prefault(0),
        })).prefault({}),
        已购道具: z.object({
            母畜联名卡: z.boolean().prefault(false),
        }).prefault({}),
    }).prefault({}),
    母畜: z.record(z.string().describe('母畜名'), z.object({
        类型: z.enum(['母猪', '母牛', '母狗']),
        等级: z.coerce.number().prefault(1).transform(v => _.clamp(v, 0, 5)),
        经验: z.coerce.number().prefault(0),
        自由点数: z.coerce.number().prefault(0),
        乳房: z.coerce.number().prefault(0),
        臀部: z.coerce.number().prefault(0),
        子宫: z.coerce.number().prefault(0),
        阴道: z.coerce.number().prefault(0),
        肛门: z.coerce.number().prefault(0),
        重修次数: z.coerce.number().prefault(0),
        是否母畜化: z.boolean().prefault(true),
    })).prefault({}),
    备选母畜: z.record(z.string().describe('角色名'), z.object({
        好感度: z.coerce.number().prefault(0).transform(v => _.clamp(v, 0, 100)),
        堕落值: z.coerce.number().prefault(0).transform(v => _.clamp(v, 0, 100)),
        成功率: z.coerce.number().prefault(0).transform(v => _.clamp(v, 0, 100)),
        母畜评级: z.string().prefault('未评级'),
    })).prefault({}),
}).prefault({});
